import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

export default function Login() {
  const [isSignup, setIsSignup] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = (e) => {
    e.preventDefault();
    // Inga unga Auth logic (axios.post) varum. For now, direct navigate:
    navigate('/marketplace');
  };

  return (
    <div className="min-h-screen bg-yellow-50 flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl overflow-hidden border-b-8 border-red-600">
        <div className="bg-red-600 p-8 text-white text-center">
          <h1 className="text-3xl font-black italic">TRUCK BOARD</h1>
          <p className="text-sm opacity-80 uppercase tracking-widest mt-2">Logistics Gateway</p>
        </div>
        <form onSubmit={handleSubmit} className="p-8 space-y-4">
          <h2 className="text-2xl font-bold text-center">{isSignup ? 'Create Account' : 'Welcome Back'}</h2>
          <input type="email" placeholder="Email Address" className="w-full p-4 border-2 rounded-xl focus:border-red-600 outline-none" required />
          <input type="password" placeholder="Password" className="w-full p-4 border-2 rounded-xl focus:border-red-600 outline-none" required />
          <button className="w-full bg-black text-white py-4 rounded-xl font-black uppercase tracking-widest hover:bg-gray-800 transition">
            {isSignup ? 'Sign Up' : 'Login'}
          </button>
          <p onClick={() => setIsSignup(!isSignup)} className="text-center text-sm font-bold cursor-pointer text-red-600">
            {isSignup ? 'Already have an account? Login' : "Don't have an account? Sign Up"}
          </p>
        </form>
      </div>
    </div>
  );
}
